import os
def strip_block(s):
    out=[]; i=0; depth=0
    while i<len(s):
        if s[i:i+2]=='/-':
            depth+=1; i+=2; continue
        if s[i:i+2]=='-/' and depth>0:
            depth-=1; i+=2; continue
        if depth==0: out.append(s[i])
        i+=1
    return ''.join(out)
total=0; perfile={}
for root,_,files in os.walk("AlgebraicJacobian"):
    for f in files:
        if f.endswith(".lean"):
            p=os.path.join(root,f)
            src=open(p).read()
            nob=strip_block(src)
            c=sum(line.split('--')[0].count('sorry') for line in nob.splitlines())
